#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char buf[20];
    while (T--) {
        if (scanf("%s", buf) != 1) break;
        if (strcmp(buf, "animal") == 0) {
            printf("Animal speaks\n");
        } else if (strcmp(buf, "dog") == 0) {
            printf("Dog barks\n");
        } else if (strcmp(buf, "puppy") == 0) {
            printf("Puppy yaps\n");
        } else {
            printf("Invalid input\n");
        }
    }
    return 0;
}

