#include <bits/stdc++.h>
using namespace std;

class Animal {
public:
    virtual void speak() const { cout << "Animal speaks" << '\n'; }
    virtual ~Animal() = default;
};

class Dog : public Animal {
public:
    void speak() const override { cout << "Dog barks" << '\n'; }
};

class Puppy : public Dog {
public:
    void speak() const override { cout << "Puppy yaps" << '\n'; }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if(!(cin >> T)) return 0;
    string type;
    while (T--) {
        cin >> type;
        Animal* obj = nullptr;
        if (type == "animal") obj = new Animal();
        else if (type == "dog") obj = new Dog();
        else if (type == "puppy") obj = new Puppy();
        else { cout << "Invalid input" << '\n'; continue; }
        obj->speak();
        delete obj;
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

class Animal {
    void speak() { System.out.println("Animal speaks"); }
}

class Dog extends Animal {
    @Override
    void speak() { System.out.println("Dog barks"); }
}

class Puppy extends Dog {
    @Override
    void speak() { System.out.println("Puppy yaps"); }
}

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        for (int i = 0; i < T; i++) {
            String type = br.readLine().trim().toLowerCase();
            Animal obj;
            switch (type) {
                case "animal": obj = new Animal(); break;
                case "dog":    obj = new Dog();    break;
                case "puppy":  obj = new Puppy();  break;
                default:
                    System.out.println("Invalid input");
                    continue;
            }
            obj.speak();
        }
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    T = int(data[0])
    out = []
    for i in range(1, T + 1):
        typ = data[i].strip().lower()
        if typ == "animal":
            out.append("Animal speaks")
        elif typ == "dog":
            out.append("Dog barks")
        elif typ == "puppy":
            out.append("Puppy yaps")
        else:
            out.append("Invalid input")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

